    "arse-linux": "<span style=\"color: #81a1c1\">                      ⣀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀</span>\n<span style=\"color: #81a1c1\">⠀⣶⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⢸⣿⠀⠀⠀⠀⠀⠀⣴⣶⠀⠀⠀⠀⠀</span>\n<span style=\"color: #81a1c1\">⢸⣿⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⢸⣿⣄⠀⠀⠀⠀⣼⠟⠁⠀⠀⢀⣀⠀</span>\n<span style=\"color: #81a1c1\">⢸⣿⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⢀⡀⠀⢀⣤⡀⠀⠀⠀⠉⢻⣷⡄⠀⠀⠁⠀⢀⣤⣾⡿⠟⠀</span>\n<span style=\"color: #81a1c1\">⢸⣿⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠙⢿⣷⣿⠏⠀⠀⠀⠀⠀⠀⠹⣿⡄⠀⠀⠀⠙⠉⠁⠀⠀⠀</span>\n<span style=\"color: #81a1c1\">⢸⣿⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠹⣿⡄⠀⠀⠀⠀⠀⠀⠀⢹⣿⠀⠀⠀⠀⠠⣶⣶⣶⡶</span>\n<span style=\"color: #81a1c1\">⢸⣿⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⢹⣿⠀⠀⠀⠀⠀⠀⠀⠀⣿⡇⠀⠀⠀⠀⠀⠀⠀⠀</span>\n<span style=\"color: #81a1c1\">⢸⣿⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⢸⣿⠀⠀⠀⠀⠀⠀⠀⢠⣿⠁⠀⠀⠀⠀⠀⠀⠀⠀</span>\n<span style=\"color: #81a1c1\">⢸⣿⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⢸⣿⠂⠀⠀⠀⠀⠀⢀⣾⡏⠀⠀⠀⠀⠀⠀⠀⠀⠀</span>\n<span style=\"color: #81a1c1\">⢸⣿⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⢠⣿⠇⠀⠀⠀⠀⠀⣠⣾⠟⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀</span>\n<span style=\"color: #81a1c1\">⢸⣿⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⣠⣴⣿⣇⣀⣀⣀⣠⣴⣾⣿⡏⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀</span>\n<span style=\"color: #81a1c1\">⢸⣿⠀⠀⠀⠀⠀⣤⣤⣴⣶⣾⠿⠟⣿⡏⠙⠛⠛⠛⠋⠉⢀⣿⠁⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀</span>\n<span style=\"color: #81a1c1\">⠀⣿⡄⠀⠀⠀⠀⠈⠉⠉⠀⠀⠀⠀⣿⡇⠀⠀⠀⠀⠀⠀⢸⣿⡀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀</span>\n<span style=\"color: #81a1c1\">⠀⣿⡇⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⢿⠇⠀⠀⠀⠀⠀⠀⠘⠿⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀</span>\n<span style=\"color: #81a1c1\">⠀⠈⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀</span>",
    "artix": "<span style=\"color: #88c0d0\">                   '</span>\n<span style=\"color: #88c0d0\">                  'o'</span>\n<span style=\"color: #88c0d0\">                 'ooo'</span>\n<span style=\"color: #88c0d0\">                'ooxoo'</span>\n<span style=\"color: #88c0d0\">               'ooxxxoo'</span>\n<span style=\"color: #88c0d0\">              'oookkxxoo'</span>\n<span style=\"color: #88c0d0\">             'oiioxkkxxoo'</span>\n<span style=\"color: #88c0d0\">            ':;:iiiioxxxoo'</span>\n<span style=\"color: #88c0d0\">               `'.;::ioxxoo'</span>\n<span style=\"color: #88c0d0\">          '-.      `':;jiooo'</span>\n<span style=\"color: #88c0d0\">         'oooio-..     `'i:io'</span>\n<span style=\"color: #88c0d0\">        'ooooxxxxoio:,.   `'-;'</span>\n<span style=\"color: #88c0d0\">       'ooooxxxxxkkxoooIi:-.  `'</span>\n<span style=\"color: #88c0d0\">      'ooooxxxxxkkkkxoiiiiiji'</span>\n<span style=\"color: #88c0d0\">     'ooooxxxxxkxxoiiii:'`     .i'</span>\n<span style=\"color: #88c0d0\">    'ooooxxxxxoi:::'`       .;ioxo'</span>\n<span style=\"color: #88c0d0\">   'ooooxooi::'`         .:iiixkxxo'</span>\n<span style=\"color: #88c0d0\">  'ooooi:'`                `'';ioxxo'</span>\n<span style=\"color: #88c0d0\"> 'i:'`                          '':io'</span>\n<span style=\"color: #88c0d0\">'`                                   `'</span>",
    "artix2": "<span style=\"color: #d4d4d4\">                   .:                   </span>\n<span style=\"color: #d4d4d4\">                  .==:                  </span>\n<span style=\"color: #d4d4d4\">                 .====:                 </span>\n<span style=\"color: #d4d4d4\">                .======:                </span>\n<span style=\"color: #d4d4d4\">               .========:               </span>\n<span style=\"color: #d4d4d4\">              .==========:              </span>\n<span style=\"color: #d4d4d4\">             .============:             </span>\n<span style=\"color: #d4d4d4\">              .-===========:            </span>\n<span style=\"color: #d4d4d4\">                 .:-========:           </span>\n<span style=\"color: #d4d4d4\">          .-:.       .:======:          </span>\n<span style=\"color: #d4d4d4\">         .======:..      :-===.         </span>\n<span style=\"color: #d4d4d4\">        .============:..    .:=.        </span>\n<span style=\"color: #d4d4d4\">       .==================:..           </span>\n<span style=\"color: #d4d4d4\">      .=======================:         </span>\n<span style=\"color: #d4d4d4\">     .====================::.    .      </span>\n<span style=\"color: #d4d4d4\">     ================::.      :-===     </span>\n<span style=\"color: #d4d4d4\">    ============-:.       .:========    </span>\n<span style=\"color: #d4d4d4\">   ========-:.           :-==========   </span>\n<span style=\"color: #d4d4d4\">  =====:.                    ..:-=====  </span>\n<span style=\"color: #d4d4d4\"> =::.                              ..:: </span>\n",
    "artix2_small": "<span style=\"color: #88c0d0\">      /\\</span>\n<span style=\"color: #88c0d0\">     /  \\</span>\n<span style=\"color: #88c0d0\">    /`'.,\\</span>\n<span style=\"color: #88c0d0\">   /     ',</span>\n<span style=\"color: #88c0d0\">  /      ,`\\</span>\n<span style=\"color: #88c0d0\"> /   ,.'`.  \\</span>\n<span style=\"color: #88c0d0\">/.,'`     `'.\\</span>\n",
    "artix_small": "<span style=\"color: #88c0d0\">            '</span>\n<span style=\"color: #88c0d0\">           'A'</span>\n<span style=\"color: #88c0d0\">          'ooo'</span>\n<span style=\"color: #88c0d0\">         'ookxo'</span>\n<span style=\"color: #88c0d0\">         `ookxxo'</span>\n<span style=\"color: #88c0d0\">       '.   `ooko'</span>\n<span style=\"color: #88c0d0\">      'ooo`.   `oo'</span>\n<span style=\"color: #88c0d0\">     'ooxxxoo`.   `'</span>\n<span style=\"color: #88c0d0\">    'ookxxxkooo.`   .</span>\n<span style=\"color: #88c0d0\">   'ookxxkoo'`   .'oo'</span>\n<span style=\"color: #88c0d0\">  'ooxoo'`     .:ooxxo'</span>\n<span style=\"color: #88c0d0\"> 'io'`             `'oo'</span>\n<span style=\"color: #88c0d0\">'`                     `'</span>\n",
    "arya": "<span style=\"color: #a3be8c\">                `oyyy/</span><span style=\"color: #bf616a\">-yyyyyy+</span>\n<span style=\"color: #a3be8c\">               -syyyy/</span><span style=\"color: #bf616a\">-yyyyyy+</span>\n<span style=\"color: #a3be8c\">              .syyyyy/</span><span style=\"color: #bf616a\">-yyyyyy+</span>\n<span style=\"color: #a3be8c\">              :yyyyyy/</span><span style=\"color: #bf616a\">-yyyyyy+</span>\n<span style=\"color: #a3be8c\">           `/ :yyyyyy/</span><span style=\"color: #bf616a\">-yyyyyy+</span>\n<span style=\"color: #a3be8c\">          .+s :yyyyyy/</span><span style=\"color: #bf616a\">-yyyyyy+</span>\n<span style=\"color: #a3be8c\">         .oys :yyyyyy/</span><span style=\"color: #bf616a\">-yyyyyy+</span>\n<span style=\"color: #a3be8c\">        -oyys :yyyyyy/</span><span style=\"color: #bf616a\">-yyyyyy+</span>\n<span style=\"color: #a3be8c\">       :syyys :yyyyyy/</span><span style=\"color: #bf616a\">-yyyyyy+</span>\n<span style=\"color: #a3be8c\">      /syyyys :yyyyyy/</span><span style=\"color: #bf616a\">-yyyyyy+</span>\n<span style=\"color: #a3be8c\">     +yyyyyys :yyyyyy/</span><span style=\"color: #bf616a\">-yyyyyy+</span>\n<span style=\"color: #a3be8c\">   .oyyyyyyo. :yyyyyy/</span><span style=\"color: #bf616a\">-yyyyyy+ ---------</span>\n<span style=\"color: #a3be8c\">  .syyyyyy+`  :yyyyyy/</span><span style=\"color: #bf616a\">-yyyyy+-+syyyyyyyy</span>\n<span style=\"color: #a3be8c\"> -syyyyyy/    :yyyyyy/</span><span style=\"color: #bf616a\">-yyys:.syyyyyyyyyy</span>\n<span style=\"color: #a3be8c\">:syyyyyy/     :yyyyyy/</span><span style=\"color: #bf616a\">-yyo.:syyyyyyyyyyy</span>",
